class SummaryRanges {
    set<int> nums;
public:
    SummaryRanges() {}

    void addNum(int value) {
        nums.insert(value);
    }

    vector<vector<int>> getIntervals() {
        vector<vector<int>> res;
        if (nums.empty()) return res;
        int start = *nums.begin(), end = start;
        for (auto it = next(nums.begin()); it != nums.end(); ++it) {
            if (*it == end + 1) {
                end = *it;
            } else {
                res.push_back({start, end});
                start = end = *it;
            }
        }
        res.push_back({start, end});
        return res;
    }
};
```
efficiency: HIGH
time complexity: addNum O(log N), getIntervals O(N)
space complexity: O(N)
energy implications: LOW
explanation: Uses a sorted set to store unique numbers; addNum is a logarithmic-time insertion, getIntervals performs a single linear scan to build intervals. Simple, cache-friendly, and optimal for the given constraints.

